mapper.update:
UPDATE employee
user_id = #{userId}, emp_no = #{empNo}, name = #{name}, email = #{email}, phone = #{phone}, department = #{department}, status = #{status}, remark = #{remark}, update_time = NOW()
WHERE id = #{id}

mapper.select:
SELECT DISTINCT e.id, e.user_id, e.emp_no, e.name, e.email, e.phone, e.department, e.status, e.remark, e.create_time, e.update_time FROM employee e
INNER JOIN employee_type_rel r ON r.employee_id = e.id AND r.type_code = #{typeCode}
AND e.status = #{status}
AND ( e.name LIKE CONCAT('%', #{keyword}, '%') OR e.email LIKE CONCAT('%', #{keyword}, '%') OR e.emp_no LIKE CONCAT('%', #{keyword}, '%') OR e.phone LIKE CONCAT('%', #{keyword}, '%') OR e.department LIKE CONCAT('%', #{keyword}, '%') )
ORDER BY e.id DESC
